'use client'

import React, { createContext, useContext, useState, useCallback, useEffect, useRef } from 'react'
import { Deck, DeckCard, DeckValidation, DeckStats, DeckFormat } from '@/types/deck'
import { useFeedback } from '@/hooks/useFeedback'
import { validateDeck, useRealtimeDeckValidation, GAME_FORMATS } from '@/lib/validation/deck-validation'
import { useCustomer } from '@/hooks/useCustomer'
import { getGames } from '@/lib/data/cards'
import { customerBackendAPI } from '@/lib/api/customer-backend'

interface DeckBuilderContextValue {
  deck: Deck | null
  isDirty: boolean
  isLoading: boolean
  isSaving: boolean
  validation: DeckValidation
  stats: DeckStats
  format: DeckFormat | null
  
  // Deck operations
  loadDeck: (deckId: string) => Promise<void>
  loadDeckForEdit: (deckId: string) => Promise<void>
  createDeck: (name: string, game: string, format: string) => Promise<void>
  saveDeck: () => Promise<void>
  deleteDeck: () => Promise<void>
  
  // Card operations
  addCard: (card: any, zone: 'main' | 'sideboard' | 'commander' | 'extra' | 'leader' | 'don' | 'prize', quantity?: number) => void
  removeCard: (catalogSku: string, zone: string, quantity?: number) => void
  moveCard: (catalogSku: string, fromZone: string, toZone: string, quantity?: number) => void
  updateCardQuantity: (catalogSku: string, zone: string, newQuantity: number) => void
  
  // Deck metadata
  updateDeckName: (name: string) => void
  updateDeckDescription: (description: string) => void
  togglePublicVisibility: () => void
  
  // Validation
  validateDeck: () => void
  getFormatRules: () => DeckFormat | null
  realtimeValidation: ReturnType<typeof useRealtimeDeckValidation>
  
  // Import/Export
  importDeck: (format: string, data: string) => Promise<void>
  exportDeck: (format: string) => Promise<string>
  
  // Undo/Redo
  canUndo: boolean
  canRedo: boolean
  undo: () => void
  redo: () => void
  
  // Clear/Reset
  clearDeck: () => void
  resetDeck: () => void
}

const DeckBuilderContext = createContext<DeckBuilderContextValue | undefined>(undefined)

export function DeckBuilderProvider({ children }: { children: React.ReactNode }) {
  const [deck, setDeck] = useState<Deck | null>(null)
  const [isDirty, setIsDirty] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [isSaving, setIsSaving] = useState(false)
  const [validation, setValidation] = useState<DeckValidation>({ isValid: true, errors: [] })
  const realtimeValidation = useRealtimeDeckValidation(deck)
  const [stats, setStats] = useState<DeckStats>({
    totalCards: 0,
    mainDeckSize: 0,
    sideboardSize: 0,
  })
  const [format, setFormat] = useState<DeckFormat | null>(null)
  
  // Undo/Redo history
  const [history, setHistory] = useState<Deck[]>([])
  const [historyIndex, setHistoryIndex] = useState(-1)
  const autoSaveTimer = useRef<NodeJS.Timeout | null>(null)
  
  const { executeWithFeedback } = useFeedback('deck-builder')
  const { customer, isAuthenticated } = useCustomer()
  
  // Calculate stats whenever deck changes
  useEffect(() => {
    if (!deck) return
    
    const newStats = calculateDeckStats(deck)
    setStats(newStats)
    
    // Auto-validate on changes using new validation system
    const newValidation = validateDeck(deck)
    setValidation({
      isValid: newValidation.isValid,
      errors: newValidation.errors.map(error => ({
        zone: error.zone || 'main',
        type: error.category,
        message: error.message,
        cardSku: error.cardSku
      })),
      warnings: newValidation.warnings.map(warning => ({
        zone: warning.zone || 'main', 
        type: warning.category,
        message: warning.message,
        cardSku: warning.cardSku
      }))
    })
    
    // Update format rules
    if (deck.game && deck.format) {
      const gameFormats = GAME_FORMATS[deck.game as keyof typeof GAME_FORMATS] as any
      const formatRules = gameFormats?.[deck.format] as any
      if (formatRules) {
        setFormat({
          name: deck.format,
          game: deck.game,
          minDeckSize: formatRules.minDeckSize,
          maxDeckSize: formatRules.maxDeckSize || undefined,
          sideboardSize: formatRules.sideboardSize || 0,
          maxCopies: formatRules.maxCopies,
          bannedCards: formatRules.bannedCards || [],
          restrictedCards: formatRules.restrictedCards || []
        })
      }
    }
  }, [deck, format]) // eslint-disable-line react-hooks/exhaustive-deps
  
  // Auto-save functionality
  useEffect(() => {
    if (isDirty && deck?.id) {
      if (autoSaveTimer.current) {
        clearTimeout(autoSaveTimer.current)
      }
      
      autoSaveTimer.current = setTimeout(() => {
        saveDeck()
      }, 3000) // Auto-save after 3 seconds of inactivity
    }
    
    return () => {
      if (autoSaveTimer.current) {
        clearTimeout(autoSaveTimer.current)
      }
    }
  }, [isDirty, deck]) // eslint-disable-line react-hooks/exhaustive-deps
  
  const calculateDeckStats = useCallback((deck: Deck): DeckStats => {
    const stats: DeckStats = {
      totalCards: 0,
      mainDeckSize: 0,
      sideboardSize: 0,
      commanderSize: 0,
      extraDeckSize: 0,
      leaderSize: 0,
      donDeckSize: 0,
      prizeCardCount: 0,
      averageCmc: 0,
      manaCurve: {},
      colorDistribution: {},
      typeDistribution: {},
      rarityDistribution: {},
    }
    
    // Calculate main deck stats
    deck.cards.main.forEach(card => {
      stats.mainDeckSize += card.quantity
      stats.totalCards += card.quantity
      
      // Mana curve (MTG specific)
      if (card.card.cmc !== undefined) {
        const cmc = Math.min(card.card.cmc, 7) // Group 7+ together
        stats.manaCurve![cmc] = (stats.manaCurve![cmc] || 0) + card.quantity
      }
      
      // Colors
      if (card.card.colors) {
        card.card.colors.forEach(color => {
          stats.colorDistribution![color] = (stats.colorDistribution![color] || 0) + card.quantity
        })
      }
      
      // Types
      if (card.card.type_line) {
        const mainType = card.card.type_line.split(' — ')[0]
        stats.typeDistribution![mainType] = (stats.typeDistribution![mainType] || 0) + card.quantity
      }
      
      // Rarity
      if (card.card.rarity) {
        stats.rarityDistribution![card.card.rarity] = 
          (stats.rarityDistribution![card.card.rarity] || 0) + card.quantity
      }
    })
    
    // Calculate sideboard stats
    if (deck.cards.sideboard) {
      deck.cards.sideboard.forEach(card => {
        stats.sideboardSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate commander stats
    if (deck.cards.commander) {
      deck.cards.commander.forEach(card => {
        stats.commanderSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate extra deck stats
    if (deck.cards.extra) {
      deck.cards.extra.forEach(card => {
        stats.extraDeckSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate leader stats
    if (deck.cards.leader) {
      deck.cards.leader.forEach(card => {
        stats.leaderSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate DON!! deck stats
    if (deck.cards.don) {
      deck.cards.don.forEach(card => {
        stats.donDeckSize! += card.quantity
        stats.totalCards += card.quantity
      })
    }

    // Calculate prize card stats
    if (deck.cards.prize) {
      deck.cards.prize.forEach(card => {
        stats.prizeCardCount! += card.quantity
        stats.totalCards += card.quantity
      })
    }
    
    // Calculate average CMC
    if (stats.manaCurve && Object.keys(stats.manaCurve).length > 0) {
      let totalCmc = 0
      let totalCards = 0
      Object.entries(stats.manaCurve).forEach(([cmc, count]) => {
        totalCmc += parseInt(cmc) * count
        totalCards += count
      })
      stats.averageCmc = totalCards > 0 ? totalCmc / totalCards : 0
    }
    
    return stats
  }, [])
  
  const validateDeckManually = useCallback(() => {
    if (!deck) return
    
    const result = validateDeck(deck)
    setValidation({
      isValid: result.isValid,
      errors: result.errors.map(error => ({
        zone: error.zone || 'main',
        type: error.category,
        message: error.message,
        cardSku: error.cardSku
      })),
      warnings: result.warnings.map(warning => ({
        zone: warning.zone || 'main',
        type: warning.category, 
        message: warning.message,
        cardSku: warning.cardSku
      }))
    })
  }, [deck])
  
  const getFormatRules = useCallback((): DeckFormat | null => {
    if (!deck?.game || !deck?.format) return null
    
    const gameFormats = GAME_FORMATS[deck.game as keyof typeof GAME_FORMATS] as any
    const formatRules = gameFormats?.[deck.format] as any
    
    if (!formatRules) return null
    
    return {
      name: deck.format,
      game: deck.game,
      minDeckSize: formatRules.minDeckSize,
      maxDeckSize: formatRules.maxDeckSize || undefined,
      sideboardSize: formatRules.sideboardSize || 0,
      maxCopies: formatRules.maxCopies,
      bannedCards: formatRules.bannedCards || [],
      restrictedCards: formatRules.restrictedCards || []
    }
  }, [deck])
  
  const isBasicLand = (cardName: string): boolean => {
    const basicLands = ['Plains', 'Island', 'Swamp', 'Mountain', 'Forest', 'Wastes']
    return basicLands.includes(cardName)
  }
  
  const addToHistory = useCallback((newDeck: Deck) => {
    setHistory(prev => {
      const newHistory = prev.slice(0, historyIndex + 1)
      newHistory.push(newDeck)
      // Limit history to 50 entries
      if (newHistory.length > 50) {
        newHistory.shift()
      }
      return newHistory
    })
    setHistoryIndex(prev => Math.min(prev + 1, 49))
  }, [historyIndex])
  
  // Cleanup loading states on unmount to prevent stuck loading overlays
  useEffect(() => {
    return () => {
      if (autoSaveTimer.current) {
        clearTimeout(autoSaveTimer.current)
      }
      // Clear any pending loading states
      setIsLoading(false)
      setIsSaving(false)
    }
  }, [])
  
  const loadDeck = useCallback(async (deckId: string) => {
    try {
      await executeWithFeedback(async () => {
        setIsLoading(true)
        try {
        // Load deck via API route with proper authentication
        const response = await fetch(`/api/decks/${deckId}`, {
          method: 'GET',
          credentials: 'include',
          headers: {
            'Content-Type': 'application/json',
          },
        })

        if (!response.ok) {
          const errorData = await response.json()
          throw new Error(errorData.error || 'Failed to load deck')
        }

        const result = await response.json()
        const loadedDeck = result.data
        
        // Ensure deck has format property
        if (!loadedDeck.format) {
          loadedDeck.format = loadedDeck.formatCode || loadedDeck.formatDetails?.code || loadedDeck.formatId
        }
        
        // Ensure deck has proper card structure
        if (!loadedDeck.cards) {
          loadedDeck.cards = {
            main: [],
            sideboard: [],
            commander: [],
            extra: []
          }
        } else {
          // Ensure all card zones exist
          loadedDeck.cards.main = loadedDeck.cards.main || []
          loadedDeck.cards.sideboard = loadedDeck.cards.sideboard || []
          loadedDeck.cards.commander = loadedDeck.cards.commander || []
          loadedDeck.cards.extra = loadedDeck.cards.extra || []
        }
        
        setDeck(loadedDeck)
        setIsDirty(false)
        
        // Load format rules via API route
        const deckFormatCode = loadedDeck.formatCode || loadedDeck.formatDetails?.code
        try {
          if (deckFormatCode && deckFormatCode !== 'undefined') {
            const formatResponse = await fetch(
              `/api/formats/${loadedDeck.game}/${deckFormatCode}`, {
                method: 'GET',
                credentials: 'include',
                headers: {
                  'Content-Type': 'application/json',
                },
              }
            )
          
            if (formatResponse.ok) {
              const formatResult = await formatResponse.json()
              setFormat(formatResult)
            } else {
              console.warn(`Format rules not available for ${loadedDeck.game}/${deckFormatCode}`)
              setFormat(null)
            }
          } else {
            console.warn(`No valid format code found for deck ${loadedDeck.id}`)
            setFormat(null)
          }
        } catch (error) {
          console.warn(`Error loading format rules for ${loadedDeck.game}/${deckFormatCode}:`, error)
          setFormat(null)
        }
        
          // Initialize history
          setHistory([loadedDeck])
          setHistoryIndex(0)
        } finally {
          setIsLoading(false)
        }
      }, {
        loadingMessage: 'Loading deck...',
        successMessage: 'Deck loaded successfully',
        errorMessage: 'Failed to load deck',
      })
    } catch (error) {
      // Additional error handling to ensure loading state is cleared
      setIsLoading(false)
      throw error
    }
  }, [executeWithFeedback])
  
  const loadDeckForEdit = useCallback(async (deckId: string) => {
    const maxRetries = 3
    const baseDelay = 1000
    
    const fetchWithRetry = async (attempt: number = 1): Promise<Response> => {
      try {
        console.log(`Loading deck for edit (attempt ${attempt}):`, deckId)
        
        // Load deck for editing via dedicated edit API route
        const response = await fetch(`/api/decks/${deckId}/edit`, {
          method: 'GET',
          credentials: 'include',
          headers: {
            'Content-Type': 'application/json',
          },
          // Add timeout to prevent hanging
          signal: AbortSignal.timeout(30000) // 30 second timeout
        })
        
        return response
      } catch (error) {
        console.error(`Fetch attempt ${attempt} failed:`, error)
        
        // Don't retry certain types of errors
        if (error instanceof Error) {
          if (error.name === 'AbortError') {
            // Timeout - retry with longer timeout on subsequent attempts
            if (attempt < maxRetries) {
              console.log(`Request timed out, retrying in ${baseDelay * attempt}ms...`)
              await new Promise(resolve => setTimeout(resolve, baseDelay * attempt))
              return fetchWithRetry(attempt + 1)
            }
          }
          
          // Network errors - retry
          if (error.message.includes('fetch failed') || error.message.includes('Failed to fetch')) {
            if (attempt < maxRetries) {
              console.log(`Network error, retrying in ${baseDelay * attempt}ms...`)
              await new Promise(resolve => setTimeout(resolve, baseDelay * attempt))
              return fetchWithRetry(attempt + 1)
            }
          }
        }
        
        throw error
      }
    }
    
    try {
      await executeWithFeedback(async () => {
        // Remove manual setIsLoading since executeWithFeedback handles it
        const response = await fetchWithRetry()

        if (!response.ok) {
          let errorData
          try {
            errorData = await response.json()
          } catch {
            errorData = { error: 'Unknown error', message: 'Failed to parse error response' }
          }
          
          console.error('Failed to load deck for editing:', errorData)
          
          // Handle specific error types with better user messages
          if (response.status === 401) {
            if (errorData.redirect) {
              // Redirect to login if session expired
              window.location.href = `/user/register?returnTo=${encodeURIComponent(window.location.pathname)}`
              return
            }
            throw new Error(errorData.message || 'Authentication required. Please log in to edit decks.')
          }
          
          if (response.status === 403) {
            throw new Error(errorData.message || 'You can only edit your own decks')
          }
          
          if (response.status === 404) {
            throw new Error(errorData.message || 'Deck not found')
          }
          
          if (response.status === 503 && errorData.retryable) {
            throw new Error(errorData.message || 'Service temporarily unavailable. Please try again.')
          }
          
          throw new Error(errorData.message || errorData.error || 'Failed to load deck for editing')
        }

        const result = await response.json()
        
        if (!result.success) {
          throw new Error(result.message || 'Failed to load deck')
        }
        
        const loadedDeck = result.data
        console.log('Deck loaded for editing:', loadedDeck)
        
        // Ensure deck has format property
        if (!loadedDeck.format) {
          loadedDeck.format = loadedDeck.formatCode || loadedDeck.formatDetails?.code || loadedDeck.formatId
        }
        
        // Ensure deck has proper card structure
        if (!loadedDeck.cards) {
          loadedDeck.cards = {
            main: [],
            sideboard: [],
            commander: [],
            extra: []
          }
        } else {
          // Ensure all card zones exist
          loadedDeck.cards.main = loadedDeck.cards.main || []
          loadedDeck.cards.sideboard = loadedDeck.cards.sideboard || []
          loadedDeck.cards.commander = loadedDeck.cards.commander || []
          loadedDeck.cards.extra = loadedDeck.cards.extra || []
        }
        
        setDeck(loadedDeck)
        setIsDirty(false)
        
        // Load format rules if available (don't let this fail the main operation)
        const deckFormatCode = loadedDeck.formatCode || loadedDeck.formatDetails?.code
        try {
          if (deckFormatCode && deckFormatCode !== 'undefined') {
            const formatResponse = await fetch(
              `/api/formats/${loadedDeck.game}/${deckFormatCode}`, {
                method: 'GET',
                credentials: 'include',
                headers: {
                  'Content-Type': 'application/json',
                },
              }
            )
          
            if (formatResponse.ok) {
              const formatResult = await formatResponse.json()
              setFormat(formatResult)
            } else {
              console.warn(`Format rules not available for ${loadedDeck.game}/${deckFormatCode}`)
              setFormat(null)
            }
          } else {
            console.warn(`No format code available for deck ${loadedDeck.id}`)
            setFormat(null)
          }
        } catch (error) {
          console.warn(`Error loading format rules for ${loadedDeck.game}/${deckFormatCode}:`, error)
          setFormat(null)
        }
        
        // Initialize history for undo/redo
        setHistory([loadedDeck])
        setHistoryIndex(0)
        
      }, {
        loadingMessage: 'Loading deck for editing...',
        successMessage: 'Deck loaded for editing',
        errorMessage: 'Failed to load deck for editing',
      })
    } catch (error) {
      // Enhanced error monitoring for client-side issues
      const errorDetails = {
        timestamp: new Date().toISOString(),
        deckId,
        error: error instanceof Error ? {
          name: error.name,
          message: error.message,
          stack: error.stack,
        } : error,
        context: 'deck-builder-load-for-edit',
        userAgent: typeof window !== 'undefined' ? window.navigator.userAgent : 'unknown',
        url: typeof window !== 'undefined' ? window.location.href : 'unknown'
      }
      
      console.error('Error in loadDeckForEdit:', errorDetails)
      
      // Send to existing error monitoring if available
      if (typeof window !== 'undefined' && (window as any).errorMonitoring) {
        try {
          (window as any).errorMonitoring.captureError(errorDetails)
        } catch (monitoringError) {
          console.warn('Failed to send client error to monitoring:', monitoringError)
        }
      }
      
      throw error
    }
  }, [executeWithFeedback])
  
  const createDeck = useCallback(async (name: string, game: string, format: string) => {
    if (!customer?.id || !isAuthenticated) {
      throw new Error('User must be authenticated to create a deck')
    }

    try {
      await executeWithFeedback(async () => {
        setIsLoading(true)
        try {
        // Get game ID from game code
        const games = await getGames()
        const selectedGame = games.find(g => g.code === game)
        
        if (!selectedGame) {
          throw new Error(`Game with code "${game}" not found`)
        }

        // Ensure we have a valid format, provide defaults if needed
        const defaultFormats: { [key: string]: string } = {
          'MTG': 'Standard',
          'POKEMON': 'Standard',
          'YUGIOH': 'Advanced',
          'OPTCG': 'Standard'
        }
        
        const finalFormat = format && format !== 'undefined' ? format : defaultFormats[game] || 'Standard'
        
        const deckData = {
          name,
          userId: customer.id,
          gameId: selectedGame.id,
          formatId: finalFormat
        }
        
        const response = await fetch('/api/decks', {
          method: 'POST',
          credentials: 'include',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(deckData)
        })

        if (!response.ok) {
          const errorData = await response.json()
          throw new Error(errorData.error || 'Failed to create deck')
        }

        const result = await response.json()
        
        // Add defensive checks for response structure
        if (!result || !result.data || !result.data.deck) {
          console.error('Invalid response format:', result)
          throw new Error('Invalid response format from deck creation API')
        }
        
        const createdDeck = result.data.deck
        
        // Ensure deck has format property
        if (!createdDeck.format && finalFormat) {
          createdDeck.format = finalFormat
        }
        
        // Ensure deck has proper card structure
        if (!createdDeck.cards) {
          createdDeck.cards = {
            main: [],
            sideboard: [],
            commander: [],
            extra: []
          }
        } else {
          // Ensure all card zones exist
          createdDeck.cards.main = createdDeck.cards.main || []
          createdDeck.cards.sideboard = createdDeck.cards.sideboard || []
          createdDeck.cards.commander = createdDeck.cards.commander || []
          createdDeck.cards.extra = createdDeck.cards.extra || []
        }
        
        setDeck(createdDeck)
        setIsDirty(false)
        
        // Load format rules via API route (optional - endpoint may not exist yet)
        try {
          if (finalFormat && finalFormat !== 'undefined') {
            const formatResponse = await fetch(`/api/formats/${game}/${finalFormat}`, {
              method: 'GET',
              credentials: 'include',
              headers: {
                'Content-Type': 'application/json',
              },
            })
            
            if (formatResponse.ok) {
              const formatResult = await formatResponse.json()
              setFormat(formatResult)
            } else {
              console.warn(`Format rules not available for ${game}/${finalFormat}`)
              setFormat(null)
            }
          } else {
            console.warn(`No valid format provided: ${finalFormat}`)
            setFormat(null)
          }
        } catch (error) {
          console.warn(`Error loading format rules for ${game}/${finalFormat}:`, error)
          // Continue without format rules for now
          setFormat(null)
        }
        
          // Initialize history
          setHistory([createdDeck])
          setHistoryIndex(0)
        } finally {
          setIsLoading(false)
        }
      }, {
        loadingMessage: 'Creating deck...',
        successMessage: 'Deck created successfully',
        errorMessage: 'Failed to create deck',
      })
    } catch (error) {
      // Additional error handling to ensure loading state is cleared
      setIsLoading(false)
      throw error
    }
  }, [executeWithFeedback, customer, isAuthenticated])
  
  const saveDeck = useCallback(async () => {
    if (!deck || !isDirty) return
    
    await executeWithFeedback(async () => {
      setIsSaving(true)
      try {
        const response = await fetch(`/api/decks/${deck.id}`, {
          method: 'PATCH',
          credentials: 'include',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            cards: deck.cards,
            name: deck.name,
            description: deck.description,
            isPublic: deck.isPublic,
            tags: deck.tags,
          })
        })

        if (!response.ok) {
          const errorData = await response.json()
          throw new Error(errorData.error || 'Failed to save deck')
        }

        const result = await response.json()
        setDeck(result.data)
        setIsDirty(false)
      } finally {
        setIsSaving(false)
      }
    }, {
      loadingMessage: 'Saving deck...',
      successMessage: 'Deck saved',
      errorMessage: 'Failed to save deck',
    })
  }, [deck, isDirty, executeWithFeedback])
  
  const deleteDeck = useCallback(async () => {
    if (!deck?.id) return
    
    await executeWithFeedback(async () => {
      const response = await fetch(`/api/decks/${deck.id}`, {
        method: 'DELETE',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || 'Failed to delete deck')
      }

      setDeck(null)
      setIsDirty(false)
      setHistory([])
      setHistoryIndex(-1)
    }, {
      loadingMessage: 'Deleting deck...',
      successMessage: 'Deck deleted',
      errorMessage: 'Failed to delete deck',
    })
  }, [deck, executeWithFeedback])
  
  const addCard = useCallback((card: any, zone: 'main' | 'sideboard' | 'commander' | 'extra' | 'leader' | 'don' | 'prize', quantity = 1) => {
    if (!deck) return
    
    setDeck(prev => {
      if (!prev) return prev
      
      const newDeck = { ...prev }
      const targetZone = newDeck.cards[zone] || []
      
      // Check if card already exists in zone
      const existingCard = targetZone.find(c => c.catalogSku === card.catalogSku)
      
      if (existingCard) {
        existingCard.quantity += quantity
      } else {
        targetZone.push({
          catalogSku: card.catalogSku,
          card: {
            id: card.id,
            name: card.name,
            game: card.game,
            mana_cost: card.mana_cost,
            cmc: card.cmc,
            type_line: card.type_line,
            colors: card.colors,
            rarity: card.rarity,
            image_uris: card.image_uris,
          },
          quantity,
          zone,
        })
      }
      
      newDeck.cards[zone] = targetZone
      addToHistory(newDeck)
      setIsDirty(true)
      return newDeck
    })
  }, [deck, addToHistory])
  
  const removeCard = useCallback((catalogSku: string, zone: string, quantity = 1) => {
    if (!deck) return
    
    setDeck(prev => {
      if (!prev) return prev
      
      const newDeck = { ...prev }
      const targetZone = newDeck.cards[zone as keyof typeof newDeck.cards] as DeckCard[]
      
      if (!targetZone) return prev
      
      const cardIndex = targetZone.findIndex(c => c.catalogSku === catalogSku)
      
      if (cardIndex >= 0) {
        const card = targetZone[cardIndex]
        if (card.quantity > quantity) {
          card.quantity -= quantity
        } else {
          targetZone.splice(cardIndex, 1)
        }
        
        addToHistory(newDeck)
        setIsDirty(true)
      }
      
      return newDeck
    })
  }, [deck, addToHistory])
  
  const moveCard = useCallback((catalogSku: string, fromZone: string, toZone: string, quantity = 1) => {
    if (!deck) return
    
    setDeck(prev => {
      if (!prev) return prev
      
      const newDeck = { ...prev }
      const sourceZone = newDeck.cards[fromZone as keyof typeof newDeck.cards] as DeckCard[]
      const destZone = newDeck.cards[toZone as keyof typeof newDeck.cards] as DeckCard[]
      
      if (!sourceZone || !destZone) return prev
      
      const sourceCard = sourceZone.find(c => c.catalogSku === catalogSku)
      
      if (sourceCard) {
        // Remove from source
        if (sourceCard.quantity > quantity) {
          sourceCard.quantity -= quantity
        } else {
          const index = sourceZone.indexOf(sourceCard)
          sourceZone.splice(index, 1)
        }
        
        // Add to destination
        const destCard = destZone.find(c => c.catalogSku === catalogSku)
        if (destCard) {
          destCard.quantity += quantity
        } else {
          destZone.push({
            ...sourceCard,
            quantity,
            zone: toZone as any,
          })
        }
        
        addToHistory(newDeck)
        setIsDirty(true)
      }
      
      return newDeck
    })
  }, [deck, addToHistory])
  
  const updateCardQuantity = useCallback((catalogSku: string, zone: string, newQuantity: number) => {
    if (!deck) return
    
    setDeck(prev => {
      if (!prev) return prev
      
      const newDeck = { ...prev }
      const targetZone = newDeck.cards[zone as keyof typeof newDeck.cards] as DeckCard[]
      
      if (!targetZone) return prev
      
      const card = targetZone.find(c => c.catalogSku === catalogSku)
      
      if (card) {
        if (newQuantity <= 0) {
          const index = targetZone.indexOf(card)
          targetZone.splice(index, 1)
        } else {
          card.quantity = newQuantity
        }
        
        addToHistory(newDeck)
        setIsDirty(true)
      }
      
      return newDeck
    })
  }, [deck, addToHistory])
  
  const updateDeckName = useCallback((name: string) => {
    if (!deck) return
    
    setDeck(prev => {
      if (!prev) return prev
      const newDeck = { ...prev, name }
      addToHistory(newDeck)
      setIsDirty(true)
      return newDeck
    })
  }, [deck, addToHistory])
  
  const updateDeckDescription = useCallback((description: string) => {
    if (!deck) return
    
    setDeck(prev => {
      if (!prev) return prev
      const newDeck = { ...prev, description }
      addToHistory(newDeck)
      setIsDirty(true)
      return newDeck
    })
  }, [deck, addToHistory])
  
  const togglePublicVisibility = useCallback(() => {
    if (!deck) return
    
    setDeck(prev => {
      if (!prev) return prev
      const newDeck = { ...prev, isPublic: !prev.isPublic }
      addToHistory(newDeck)
      setIsDirty(true)
      return newDeck
    })
  }, [deck, addToHistory])
  
  const manualValidateDeck = useCallback(() => {
    if (!deck) return
    
    const result = validateDeck(deck)
    setValidation({
      isValid: result.isValid,
      errors: result.errors.map(error => ({
        zone: error.zone || 'main',
        type: error.category,
        message: error.message,
        cardSku: error.cardSku
      })),
      warnings: result.warnings.map(warning => ({
        zone: warning.zone || 'main',
        type: warning.category, 
        message: warning.message,
        cardSku: warning.cardSku
      }))
    })
  }, [deck])
  
  const getFormatRulesCallback = useCallback(() => format, [format])
  
  const importDeck = useCallback(async (format: string, data: string) => {
    await executeWithFeedback(async () => {
      const response = await fetch('/api/decks/import', {
        method: 'POST',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          format,
          data,
          game: deck?.game,
        })
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || 'Failed to import deck')
      }

      const result = await response.json()
      const importedCards = result.data
      
      setDeck(prev => {
        if (!prev) return prev
        const newDeck = { ...prev, cards: importedCards }
        addToHistory(newDeck)
        setIsDirty(true)
        return newDeck
      })
    }, {
      loadingMessage: 'Importing deck...',
      successMessage: 'Deck imported successfully',
      errorMessage: 'Failed to import deck',
    })
  }, [deck, executeWithFeedback, addToHistory])
  
  const exportDeck = useCallback(async (format: string): Promise<string> => {
    if (!deck) return ''
    
    try {
      const response = await fetch(`/api/decks/${deck.id}/export?format=${format}`, {
        method: 'GET',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
        },
      })

      if (!response.ok) {
        const errorData = await response.json()
        throw new Error(errorData.error || 'Failed to export deck')
      }

      return await response.text()
    } catch (error) {
      console.error('Error exporting deck:', error)
      throw error
    }
  }, [deck])
  
  const undo = useCallback(() => {
    if (historyIndex > 0) {
      const previousDeck = history[historyIndex - 1]
      setDeck(previousDeck)
      setHistoryIndex(historyIndex - 1)
      setIsDirty(true)
    }
  }, [history, historyIndex])
  
  const redo = useCallback(() => {
    if (historyIndex < history.length - 1) {
      const nextDeck = history[historyIndex + 1]
      setDeck(nextDeck)
      setHistoryIndex(historyIndex + 1)
      setIsDirty(true)
    }
  }, [history, historyIndex])
  
  const clearDeck = useCallback(() => {
    if (!deck) return
    
    setDeck(prev => {
      if (!prev) return prev
      const newDeck = {
        ...prev,
        cards: {
          main: [],
          sideboard: [],
          commander: [],
          extra: [],
        },
      }
      addToHistory(newDeck)
      setIsDirty(true)
      return newDeck
    })
  }, [deck, addToHistory])
  
  const resetDeck = useCallback(() => {
    if (history.length > 0) {
      const originalDeck = history[0]
      setDeck(originalDeck)
      setHistoryIndex(0)
      setIsDirty(false)
    }
  }, [history])
  
  const value: DeckBuilderContextValue = {
    deck,
    isDirty,
    isLoading,
    isSaving,
    validation,
    stats,
    format,
    loadDeck,
    loadDeckForEdit,
    createDeck,
    saveDeck,
    deleteDeck,
    addCard,
    removeCard,
    moveCard,
    updateCardQuantity,
    updateDeckName,
    updateDeckDescription,
    togglePublicVisibility,
    validateDeck: validateDeckManually,
    getFormatRules: getFormatRulesCallback,
    realtimeValidation,
    importDeck,
    exportDeck,
    canUndo: historyIndex > 0,
    canRedo: historyIndex < history.length - 1,
    undo,
    redo,
    clearDeck,
    resetDeck,
  }
  
  return (
    <DeckBuilderContext.Provider value={value}>
      {children}
    </DeckBuilderContext.Provider>
  )
}

export function useDeckBuilder() {
  const context = useContext(DeckBuilderContext)
  if (!context) {
    throw new Error('useDeckBuilder must be used within a DeckBuilderProvider')
  }
  return context
}

import type { BackendListing, CardDetailBFFResponse } from '@/types/bff'
import type { Card, CardSet, Print } from '@/types/tcg'
import { CONDITION_ORDER } from '@/types/bff'

// ─── Config ───────────────────────────────────────────────────────────────────

const CUSTOMER_BACKEND_URL =
  process.env.CUSTOMER_BACKEND_URL ??
  process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL ??
  'http://localhost:7000'

const BACKEND_STORE_URL =
  process.env.MEDUSA_BACKEND_URL ??
  process.env.NEXT_PUBLIC_MEDUSA_BACKEND_URL ??
  'http://localhost:9001'

export const LISTINGS_TIMEOUT_MS =
  process.env.NODE_ENV === 'test' ? 100 : 3000

// ─── Errors ──────────────────────────────────────────────────────────────────

export class CardNotFoundError extends Error {
  constructor(cardId: string) {
    super(`Card not found: ${cardId}`)
    this.name = 'CardNotFoundError'
  }
}

// ─── Raw API types ────────────────────────────────────────────────────────────

interface RawGame {
  id: string
  code: string
  name: string
  displayName: string
  hasColors: boolean
  hasEnergyTypes: boolean
  hasPowerToughness: boolean
  hasLevels: boolean
  etlEnabled: boolean
  createdAt: string
  updatedAt: string
}

interface RawSet {
  id: string
  gameId: string
  code: string
  name: string
  isDigital: boolean
  createdAt: string
  updatedAt: string
  [key: string]: unknown
}

interface RawPrint {
  id: string
  cardId: string
  setId: string
  number?: string
  language: string
  finish: string
  isLegalStandard: boolean
  isLegalPioneer: boolean
  isLegalModern: boolean
  isLegalLegacy: boolean
  isLegalVintage: boolean
  isLegalCommander: boolean
  isLegalPauper: boolean
  isLegalBrawl: boolean
  isLegalPokemonStandard: boolean
  isLegalPokemonExpanded: boolean
  isLegalPokemonUnlimited: boolean
  isLegalYugiohAdvanced: boolean
  isLegalYugiohTraditional: boolean
  isLegalOnePieceStandard: boolean
  createdAt: string
  updatedAt: string
  set?: RawSet
  [key: string]: unknown
}

interface RawCatalogCard {
  id: string
  gameId: string
  gameCode?: string
  oracleId: string
  oracleHash: string
  name: string
  normalizedName: string
  popularityScore: number
  totalViews: number
  totalSearches: number
  createdAt: string
  updatedAt: string
  game?: RawGame
  prints: RawPrint[]
  sets: RawSet[]
  [key: string]: unknown
}

interface RawListing {
  id: string
  catalog_sku: string
  condition: 'NM' | 'LP' | 'MP' | 'HP' | 'DMG'
  language: string
  finish: string
  price: number
  currency: string
  quantity: number
  shipping_method: string
  seller_id: string
  seller_name: string
  seller_type: 'consumer' | 'business'
  shipping_cost?: number
  shipping_location?: string
}

interface TrustData {
  rating: number
  reviewCount: number
}

// ─── Internal helpers ─────────────────────────────────────────────────────────

async function fetchCatalog(cardId: string): Promise<RawCatalogCard> {
  const response = await fetch(
    `${CUSTOMER_BACKEND_URL}/api/cards/${cardId}/details`
  )

  if (response.status === 404) {
    throw new CardNotFoundError(cardId)
  }

  if (!response.ok) {
    throw new Error(`Catalog fetch failed: ${response.status}`)
  }

  const body = await response.json()
  // customer-backend /cards/:id/details returns the card object at root level (not wrapped in { data })
  return (body.data ?? body) as RawCatalogCard
}

function buildCatalogSku(card: RawCatalogCard): string {
  const print = card.prints?.[0]
  const gameCode = card.game?.code ?? card.gameCode ?? ''
  const setCode = print?.set?.code ?? ''
  const collectorNumber = print?.number ?? ''
  return `${gameCode}-${setCode}-${collectorNumber}`
}

async function fetchListingsWithFallback(
  catalogSku: string
): Promise<{ listings: RawListing[]; unavailable: boolean }> {
  const controller = new AbortController()
  const timeout = setTimeout(() => controller.abort(), LISTINGS_TIMEOUT_MS)

  try {
    const encodedSku = encodeURIComponent(catalogSku)
    const response = await fetch(
      `${BACKEND_STORE_URL}/store/cards/listings?catalog_sku=${encodedSku}`,
      { signal: controller.signal }
    )

    if (!response.ok) {
      return { listings: [], unavailable: true }
    }

    const body = await response.json()
    return { listings: (body.data as RawListing[]) ?? [], unavailable: false }
  } catch (err) {
    return { listings: [], unavailable: true }
  } finally {
    clearTimeout(timeout)
  }
}

async function fetchTrustBatch(
  sellerIds: string[]
): Promise<Record<string, TrustData>> {
  const response = await fetch(
    `${CUSTOMER_BACKEND_URL}/api/sellers/trust/batch`,
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ sellerIds }),
    }
  )

  if (!response.ok) {
    throw new Error(`Trust batch fetch failed: ${response.status}`)
  }

  const body = await response.json()
  return (body.data as Record<string, TrustData>) ?? {}
}

function mergeListingsWithTrust(
  rawListings: RawListing[],
  trust: Record<string, TrustData>
): BackendListing[] {
  return rawListings.map(raw => {
    const trustData = trust[raw.seller_id]
    const listing: BackendListing = {
      id: raw.id,
      catalogSku: raw.catalog_sku,
      condition: raw.condition,
      language: raw.language,
      finish: raw.finish,
      price: raw.price,
      currency: raw.currency,
      quantity: raw.quantity,
      shippingMethod: raw.shipping_method,
      sellerId: raw.seller_id,
      sellerName: raw.seller_name,
      sellerType: raw.seller_type,
    }

    if (raw.shipping_cost !== undefined) {
      listing.shippingCost = raw.shipping_cost
    }
    if (raw.shipping_location !== undefined) {
      listing.shippingLocation = raw.shipping_location
    }
    if (trustData) {
      listing.sellerRating = trustData.rating
      listing.sellerReviewCount = trustData.reviewCount
    }

    return listing
  })
}

function sortListings(listings: BackendListing[]): BackendListing[] {
  return [...listings].sort((a, b) => {
    if (a.price !== b.price) return a.price - b.price
    return CONDITION_ORDER.indexOf(a.condition) - CONDITION_ORDER.indexOf(b.condition)
  })
}

function buildCardResponse(
  raw: RawCatalogCard
): CardDetailBFFResponse['card'] {
  // Build legality map from the first print's legality fields
  const print = raw.prints?.[0]
  const legality: Record<string, boolean> = {}

  if (print) {
    if (print.isLegalStandard !== undefined) legality['standard'] = print.isLegalStandard
    if (print.isLegalPioneer !== undefined) legality['pioneer'] = print.isLegalPioneer
    if (print.isLegalModern !== undefined) legality['modern'] = print.isLegalModern
    if (print.isLegalLegacy !== undefined) legality['legacy'] = print.isLegalLegacy
    if (print.isLegalVintage !== undefined) legality['vintage'] = print.isLegalVintage
    if (print.isLegalCommander !== undefined) legality['commander'] = print.isLegalCommander
    if (print.isLegalPauper !== undefined) legality['pauper'] = print.isLegalPauper
    if (print.isLegalBrawl !== undefined) legality['brawl'] = print.isLegalBrawl
    if (print.isLegalPokemonStandard !== undefined) legality['pokemonStandard'] = print.isLegalPokemonStandard
    if (print.isLegalPokemonExpanded !== undefined) legality['pokemonExpanded'] = print.isLegalPokemonExpanded
    if (print.isLegalPokemonUnlimited !== undefined) legality['pokemonUnlimited'] = print.isLegalPokemonUnlimited
    if (print.isLegalYugiohAdvanced !== undefined) legality['yugiohAdvanced'] = print.isLegalYugiohAdvanced
    if (print.isLegalYugiohTraditional !== undefined) legality['yugiohTraditional'] = print.isLegalYugiohTraditional
    if (print.isLegalOnePieceStandard !== undefined) legality['onePieceStandard'] = print.isLegalOnePieceStandard
  }

  // Convert date strings to Date objects
  const prints: Print[] = raw.prints.map(p => ({
    ...p,
    createdAt: new Date(p.createdAt),
    updatedAt: new Date(p.updatedAt),
    set: p.set
      ? { ...p.set, createdAt: new Date(p.set.createdAt), updatedAt: new Date(p.set.updatedAt) }
      : undefined,
  }))

  const sets: CardSet[] = raw.sets.map(s => ({
    ...s,
    createdAt: new Date(s.createdAt),
    updatedAt: new Date(s.updatedAt),
  }))

  return {
    ...raw,
    createdAt: new Date(raw.createdAt),
    updatedAt: new Date(raw.updatedAt),
    game: raw.game
      ? {
          ...raw.game,
          code: raw.game.code as 'MTG' | 'POKEMON' | 'YUGIOH' | 'OPTCG',
          createdAt: new Date(raw.game.createdAt),
          updatedAt: new Date(raw.game.updatedAt),
        }
      : undefined,
    prints,
    sets,
    legality,
  } as CardDetailBFFResponse['card']
}

// ─── Public API ───────────────────────────────────────────────────────────────

export async function fetchCardDetailBFF(
  cardId: string,
  catalogSkuOverride?: string
): Promise<CardDetailBFFResponse> {
  // Step 1: Catalog fetch — hard error on failure
  const rawCard = await fetchCatalog(cardId)

  // Step 2: Build catalogSku (or use override for re-fetch on print switch)
  const catalogSku = catalogSkuOverride ?? buildCatalogSku(rawCard)

  // Step 3: Fetch listings with graceful degradation
  const { listings: rawListings, unavailable } =
    await fetchListingsWithFallback(catalogSku)

  // Step 4: Fetch trust batch (deduped seller IDs) — only if there are listings
  let trust: Record<string, TrustData> = {}
  if (rawListings.length > 0) {
    const uniqueSellerIds = [...new Set(rawListings.map(l => l.seller_id))]
    try {
      trust = await fetchTrustBatch(uniqueSellerIds)
    } catch {
      // Trust failure is non-fatal — listings show without trust signals
    }
  }

  // Step 5: Merge, sort, and return
  const listings = sortListings(mergeListingsWithTrust(rawListings, trust))
  const card = buildCardResponse(rawCard)

  return { card, listings, listingsUnavailable: unavailable }
}

