const [history, setHistory] = useState<Deck[]>([])
const [historyIndex, setHistoryIndex] = useState(-1)
const autoSaveTimer = useRef<NodeJS.Timeout | null>(null)

// Owned cards tracking — useRef for the set to avoid re-render storms,
