const resetDeck = useCallback(() => {
  if (history.length > 0) {
    const originalDeck = history[0]
    setDeck(originalDeck)
    setHistoryIndex(0)
    setIsDirty(false)
  }
}, [history])

// ─── Owned cards helpers ──────────────────────────────────────────────────

const getOwnedStorageKey = useCallback((deckId: string) => `sd-owned-${deckId}`, [])

const loadOwnedCards = useCallback((deckId: string) => {
  try {
    const stored = localStorage.getItem(getOwnedStorageKey(deckId))
    if (stored) {
      const parsed = JSON.parse(stored)
      if (Array.isArray(parsed)) {
        ownedCardsRef.current = new Set(parsed)
        setOwnedCardsVersion(v => v + 1)
        return
      }
    }
  } catch {
    // Corrupt localStorage — fall back to empty set
  }
  ownedCardsRef.current = new Set()
  setOwnedCardsVersion(v => v + 1)
}, [getOwnedStorageKey])

const saveOwnedCards = useCallback((deckId: string) => {
  try {
    localStorage.setItem(
      getOwnedStorageKey(deckId),
      JSON.stringify([...ownedCardsRef.current])
    )
  } catch {
    // localStorage full or unavailable — silently degrade
  }
}, [getOwnedStorageKey])

const toggleOwned = useCallback((catalogSku: string) => {
  if (ownedCardsRef.current.has(catalogSku)) {
    ownedCardsRef.current.delete(catalogSku)
  } else {
    ownedCardsRef.current.add(catalogSku)
  }
  setOwnedCardsVersion(v => v + 1)
  if (deck?.id) {
    saveOwnedCards(deck.id)
  }
}, [deck?.id, saveOwnedCards])

const isOwned = useCallback((catalogSku: string): boolean => {
  // Read ownedCardsVersion to subscribe to changes
  void ownedCardsVersion
  return ownedCardsRef.current.has(catalogSku)
}, [ownedCardsVersion])

const getMissingCards = useCallback((): MissingCard[] => {
  // Read ownedCardsVersion to subscribe to changes
  void ownedCardsVersion
  if (!deck) return []

  const missingMap = new Map<string, MissingCard>()

  const allZones: (keyof DeckZone)[] = ['main', 'sideboard', 'commander', 'extra', 'leader', 'don', 'prize']

  for (const zoneName of allZones) {
    const zoneCards = deck.cards[zoneName]
    if (!zoneCards) continue

    for (const card of zoneCards) {
      if (ownedCardsRef.current.has(card.catalogSku)) continue

      const existing = missingMap.get(card.catalogSku)
