import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { render, screen, act } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import React from 'react'
import { DeckBuilderProvider, useDeckBuilder } from '../DeckBuilderContext'
import type { Deck } from '@/types/deck'

// ─── Mocks ────────────────────────────────────────────────────────────────────

vi.mock('@/hooks/useFeedback', () => ({
  useFeedback: () => ({
    executeWithFeedback: async (fn: () => Promise<void>) => fn(),
  }),
}))

vi.mock('@/hooks/useCustomer', () => ({
  useCustomer: () => ({
    customer: { id: 'cust-1' },
    isAuthenticated: true,
  }),
}))

vi.mock('@/lib/validation/deck-validation', () => ({
  validateDeck: () => ({ isValid: true, errors: [], warnings: [] }),
  useRealtimeDeckValidation: () => ({ isValid: true, errors: [], warnings: [] }),
  GAME_FORMATS: {},
}))

vi.mock('@/lib/data/cards', () => ({
  getGames: () => Promise.resolve([]),
}))

vi.mock('@/lib/api/customer-backend', () => ({
  customerBackendAPI: {},
}))

// ─── Helpers ──────────────────────────────────────────────────────────────────

function makeDeck(overrides: Partial<Deck> = {}): Deck {
  return {
    id: 'deck-1',
    name: 'Test Deck',
    game: 'MTG',
    format: 'Standard',
    isPublic: false,
    isValid: true,
    createdAt: new Date(),
    updatedAt: new Date(),
    cards: {
      main: [
        {
          catalogSku: 'MTG-SET1-001',
          card: { id: 'c1', name: 'Lightning Bolt', game: 'MTG' },
          quantity: 4,
          zone: 'main',
        },
        {
          catalogSku: 'MTG-SET1-002',
          card: { id: 'c2', name: 'Counterspell', game: 'MTG' },
          quantity: 2,
          zone: 'main',
        },
      ],
      sideboard: [
        {
          catalogSku: 'MTG-SET1-001',
          card: { id: 'c1', name: 'Lightning Bolt', game: 'MTG' },
          quantity: 1,
          zone: 'sideboard',
        },
        {
          catalogSku: 'MTG-SET1-003',
          card: { id: 'c3', name: 'Dark Ritual', game: 'MTG' },
          quantity: 3,
          zone: 'sideboard',
        },
      ],
    },
    ...overrides,
  }
}

/** A test component that exposes context values for assertion */
function TestHarness({
  initialDeck,
  onContextReady,
}: {
  initialDeck?: Deck
  onContextReady?: (ctx: ReturnType<typeof useDeckBuilder>) => void
}) {
  const ctx = useDeckBuilder()

  React.useEffect(() => {
    onContextReady?.(ctx)
  })

  return (
    <div>
      <span data-testid="missing-count">{ctx.getMissingCards().length}</span>
      <span data-testid="missing-json">
        {JSON.stringify(ctx.getMissingCards())}
      </span>
    </div>
  )
}

function renderWithProvider(initialDeck?: Deck) {
  let ctxRef: ReturnType<typeof useDeckBuilder> | undefined

  const utils = render(
    <DeckBuilderProvider>
      <TestHarness
        initialDeck={initialDeck}
        onContextReady={(ctx) => {
          ctxRef = ctx
        }}
      />
    </DeckBuilderProvider>
  )

  return {
    ...utils,
    getCtx: () => ctxRef!,
  }
}

// ─── localStorage mock ────────────────────────────────────────────────────────

let localStorageStore: Record<string, string> = {}

beforeEach(() => {
  localStorageStore = {}
  vi.spyOn(Storage.prototype, 'getItem').mockImplementation(
    (key: string) => localStorageStore[key] ?? null
  )
  vi.spyOn(Storage.prototype, 'setItem').mockImplementation(
    (key: string, value: string) => {
      localStorageStore[key] = value
    }
  )
  vi.spyOn(Storage.prototype, 'removeItem').mockImplementation(
    (key: string) => {
      delete localStorageStore[key]
    }
  )
})

afterEach(() => {
  vi.restoreAllMocks()
})

// ─── Tests ────────────────────────────────────────────────────────────────────

describe('DeckBuilderContext — Ownership', () => {
  it('toggles owned state on/off for a card', () => {
    const { getCtx } = renderWithProvider()
    const ctx = getCtx()

    expect(ctx.isOwned('MTG-SET1-001')).toBe(false)

    act(() => {
      ctx.toggleOwned('MTG-SET1-001')
    })
    expect(getCtx().isOwned('MTG-SET1-001')).toBe(true)

    act(() => {
      getCtx().toggleOwned('MTG-SET1-001')
    })
    expect(getCtx().isOwned('MTG-SET1-001')).toBe(false)
  })

  it('getMissingCards() excludes owned cards', async () => {
    // We need to set the deck state directly. Since loadDeck requires API calls,
    // we'll test through the context by mocking fetch for loadDeck.
    const deck = makeDeck()
    const deckResponse = {
      data: deck,
    }

    vi.spyOn(globalThis, 'fetch').mockImplementation(async (url) => {
      const urlStr = typeof url === 'string' ? url : url.toString()
      if (urlStr.includes('/api/decks/deck-1')) {
        return new Response(JSON.stringify(deckResponse), {
          status: 200,
          headers: { 'Content-Type': 'application/json' },
        })
