    const missing = getCtx().getMissingCards()

    // Lightning Bolt: 4 in main + 1 in sideboard = 5 total
    const bolt = missing.find((m) => m.catalogSku === 'MTG-SET1-001')
    expect(bolt).toBeDefined()
    expect(bolt!.quantity).toBe(5)
    expect(bolt!.cardName).toBe('Lightning Bolt')

    // Counterspell: 2 in main
    const counter = missing.find((m) => m.catalogSku === 'MTG-SET1-002')
    expect(counter?.quantity).toBe(2)

    // Dark Ritual: 3 in sideboard
    const ritual = missing.find((m) => m.catalogSku === 'MTG-SET1-003')
