    expect(getCtx().isOwned('MTG-SET1-001')).toBe(true)
    expect(getCtx().isOwned('MTG-SET1-003')).toBe(true)

    // Verify localStorage was written
    expect(localStorageStore['sd-owned-deck-1']).toBeDefined()
    const stored = JSON.parse(localStorageStore['sd-owned-deck-1'])
    expect(stored).toContain('MTG-SET1-001')
    expect(stored).toContain('MTG-SET1-003')

    // Unmount and remount — state should restore from localStorage
    unmount()

    const { getCtx: getCtx2 } = renderWithProvider()

    await act(async () => {
      await getCtx2().loadDeck('deck-1')
    })

    expect(getCtx2().isOwned('MTG-SET1-001')).toBe(true)
    expect(getCtx2().isOwned('MTG-SET1-003')).toBe(true)
    expect(getCtx2().isOwned('MTG-SET1-002')).toBe(false)

    // Missing cards should exclude the two owned ones
    const missing = getCtx2().getMissingCards()
    expect(missing).toHaveLength(1)
    expect(missing[0].catalogSku).toBe('MTG-SET1-002')
  })

  it('empty deck returns empty missing list', () => {
    const { getCtx } = renderWithProvider()
    // No deck loaded — getMissingCards should return []
    expect(getCtx().getMissingCards()).toEqual([])
  })

  it('all cards owned returns empty missing list', async () => {
    const deck = makeDeck({
