/**
 * @vitest-environment node
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { NextRequest } from 'next/server'

// ─── Test data ────────────────────────────────────────────────────────────────

function makeRawListing(overrides: Record<string, unknown> = {}) {
  return {
    id: `listing-${Math.random().toString(36).slice(2, 8)}`,
    catalog_sku: 'MTG-SET1-001',
    condition: 'NM',
    language: 'en',
    finish: 'nonfoil',
    price: 500,
    currency: 'usd',
    quantity: 4,
    shipping_method: 'standard',
    seller_id: 'seller-1',
    seller_name: 'Card Shop A',
    seller_type: 'business',
    ...overrides,
  }
}

function makeRequest(body: unknown): NextRequest {
  return new NextRequest('http://localhost/api/optimizer/listings', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  })
}

// ─── Setup ────────────────────────────────────────────────────────────────────

let fetchMock: ReturnType<typeof vi.fn>

beforeEach(() => {
  fetchMock = vi.fn()
  vi.stubGlobal('fetch', fetchMock)
})

afterEach(() => {
  vi.restoreAllMocks()
})

// Dynamic import to get fresh module per test (picks up mocked fetch)
async function getRoute() {
  // Clear module cache to pick up fresh fetch mock
  const mod = await import('../listings/route')
  return mod
}

// ─── Tests ────────────────────────────────────────────────────────────────────

describe('POST /api/optimizer/listings', () => {
  it('returns grouped listings for 3 SKUs', async () => {
    const { POST } = await getRoute()

    fetchMock.mockImplementation(async (url: string | URL) => {
      const urlStr = url.toString()
      if (urlStr.includes('/store/cards/listings')) {
        const skuMatch = urlStr.match(/catalog_sku=([^&]+)/)
        const sku = skuMatch ? decodeURIComponent(skuMatch[1]) : ''
        return new Response(
          JSON.stringify({
            data: [makeRawListing({ catalog_sku: sku, seller_id: 'seller-1' })],
          }),
          { status: 200 }
        )
      }
      if (urlStr.includes('/api/sellers/trust/batch')) {
        return new Response(
          JSON.stringify({
            data: {
              'seller-1': { rating: 99.5, reviewCount: 200 },
            },
          }),
          { status: 200 }
        )
      }
      return new Response('Not found', { status: 404 })
    })

    const req = makeRequest({ catalogSkus: ['SKU-1', 'SKU-2', 'SKU-3'] })
    const response = await POST(req)
    const body = await response.json()

    expect(response.status).toBe(200)
    expect(Object.keys(body.listings)).toHaveLength(3)
    expect(body.errors).toEqual([])
    expect(body.timestamp).toBeGreaterThan(0)

    // Verify trust data was merged
    const firstListings = body.listings['SKU-1']
    expect(firstListings[0].sellerRating).toBe(99.5)
    expect(firstListings[0].sellerReviewCount).toBe(200)
  })

  it('fetches 10 SKUs in batches of 5 (concurrency limit)', async () => {
    const { POST } = await getRoute()

    const callTimestamps: number[] = []

    fetchMock.mockImplementation(async (url: string | URL) => {
      const urlStr = url.toString()
      if (urlStr.includes('/store/cards/listings')) {
        callTimestamps.push(Date.now())
        // Small delay to make timing observable
        await new Promise((r) => setTimeout(r, 10))
        const skuMatch = urlStr.match(/catalog_sku=([^&]+)/)
        const sku = skuMatch ? decodeURIComponent(skuMatch[1]) : ''
        return new Response(
          JSON.stringify({ data: [makeRawListing({ catalog_sku: sku })] }),
          { status: 200 }
        )
      }
      if (urlStr.includes('/api/sellers/trust/batch')) {
        return new Response(JSON.stringify({ data: {} }), { status: 200 })
      }
      return new Response('Not found', { status: 404 })
    })

    const skus = Array.from({ length: 10 }, (_, i) => `SKU-${i}`)
    const req = makeRequest({ catalogSkus: skus })
    const response = await POST(req)
    const body = await response.json()

    expect(response.status).toBe(200)
    expect(Object.keys(body.listings)).toHaveLength(10)

    // Verify listing fetches were made (10 listing calls + 1 trust batch)
    const listingCalls = fetchMock.mock.calls.filter((c: [string | URL]) =>
      c[0].toString().includes('/store/cards/listings')
    )
    expect(listingCalls).toHaveLength(10)
  })

  it('handles partial failure — 1 of 3 SKUs fails, others still returned', async () => {
    const { POST } = await getRoute()

    fetchMock.mockImplementation(async (url: string | URL) => {
      const urlStr = url.toString()
      if (urlStr.includes('/store/cards/listings')) {
        const skuMatch = urlStr.match(/catalog_sku=([^&]+)/)
        const sku = skuMatch ? decodeURIComponent(skuMatch[1]) : ''
        if (sku === 'SKU-FAIL') {
          return new Response('Server Error', { status: 500 })
        }
        return new Response(
          JSON.stringify({
            data: [makeRawListing({ catalog_sku: sku, seller_id: 'seller-1' })],
          }),
          { status: 200 }
        )
      }
      if (urlStr.includes('/api/sellers/trust/batch')) {
        return new Response(JSON.stringify({ data: {} }), { status: 200 })
      }
      return new Response('Not found', { status: 404 })
    })

    const req = makeRequest({ catalogSkus: ['SKU-OK-1', 'SKU-FAIL', 'SKU-OK-2'] })
    const response = await POST(req)
    const body = await response.json()

    expect(response.status).toBe(200)
    expect(Object.keys(body.listings)).toHaveLength(2)
    expect(body.listings['SKU-OK-1']).toBeDefined()
    expect(body.listings['SKU-OK-2']).toBeDefined()
    expect(body.errors).toContain('SKU-FAIL')
  })

  it('merges trust data onto listings', async () => {
    const { POST } = await getRoute()

    fetchMock.mockImplementation(async (url: string | URL) => {
      const urlStr = url.toString()
      if (urlStr.includes('/store/cards/listings')) {
        return new Response(
          JSON.stringify({
            data: [
              makeRawListing({ seller_id: 'seller-A' }),
              makeRawListing({ seller_id: 'seller-B' }),
            ],
          }),
          { status: 200 }
        )
      }
      if (urlStr.includes('/api/sellers/trust/batch')) {
        return new Response(
          JSON.stringify({
            data: {
              'seller-A': { rating: 98.0, reviewCount: 150 },
              'seller-B': { rating: 95.5, reviewCount: 50 },
            },
          }),
          { status: 200 }
        )
      }
      return new Response('Not found', { status: 404 })
    })

    const req = makeRequest({ catalogSkus: ['SKU-1'] })
    const response = await POST(req)
    const body = await response.json()

    const listings = body.listings['SKU-1']
    expect(listings).toHaveLength(2)

    const sellerA = listings.find((l: any) => l.sellerId === 'seller-A')
    expect(sellerA.sellerRating).toBe(98.0)
    expect(sellerA.sellerReviewCount).toBe(150)

    const sellerB = listings.find((l: any) => l.sellerId === 'seller-B')
    expect(sellerB.sellerRating).toBe(95.5)
    expect(sellerB.sellerReviewCount).toBe(50)
  })

  describe('input validation', () => {
    it('rejects empty array', async () => {
      const { POST } = await getRoute()
      const req = makeRequest({ catalogSkus: [] })
      const response = await POST(req)
      expect(response.status).toBe(400)
      const body = await response.json()
      expect(body.error).toContain('must not be empty')
    })

    it('rejects non-array', async () => {
      const { POST } = await getRoute()
      const req = makeRequest({ catalogSkus: 'not-an-array' })
      const response = await POST(req)
      expect(response.status).toBe(400)
    })

    it('rejects >100 items', async () => {
      const { POST } = await getRoute()
      const skus = Array.from({ length: 101 }, (_, i) => `SKU-${i}`)
      const req = makeRequest({ catalogSkus: skus })
      const response = await POST(req)
      expect(response.status).toBe(400)
      const body = await response.json()
      expect(body.error).toContain('100')
    })
  })

  it('deduplicates input SKUs — duplicate SKUs fetched only once', async () => {
    const { POST } = await getRoute()

    fetchMock.mockImplementation(async (url: string | URL) => {
      const urlStr = url.toString()
      if (urlStr.includes('/store/cards/listings')) {
        const skuMatch = urlStr.match(/catalog_sku=([^&]+)/)
        const sku = skuMatch ? decodeURIComponent(skuMatch[1]) : ''
        return new Response(
          JSON.stringify({
            data: [makeRawListing({ catalog_sku: sku })],
          }),
          { status: 200 }
        )
      }
      if (urlStr.includes('/api/sellers/trust/batch')) {
        return new Response(JSON.stringify({ data: {} }), { status: 200 })
      }
      return new Response('Not found', { status: 404 })
    })

    // Send duplicates
    const req = makeRequest({ catalogSkus: ['SKU-1', 'SKU-1', 'SKU-2', 'SKU-2', 'SKU-2'] })
    const response = await POST(req)
    const body = await response.json()

    expect(response.status).toBe(200)
    expect(Object.keys(body.listings)).toHaveLength(2)

    // Verify only 2 listing fetches were made (not 5)
    const listingCalls = fetchMock.mock.calls.filter((c: [string | URL]) =>
      c[0].toString().includes('/store/cards/listings')
    )
    expect(listingCalls).toHaveLength(2)
  })
})

